  @TypeID = @TypeID_9d95f0cd,
  @TemplateText = @TemplateText_9d95f0cd,
  @Priority = @Priority_9d95f0cd,
  @IsActive = @IsActive_9d95f0cd,
  @ID = @ID_9d95f0cd;

GO

