SET
  @ID_34cd4a32 = '40601CCF-BDC4-465B-99D8-4DAF49ED9527'
SET
  @Namespace_34cd4a32 = N'Generic/UI/Form'
SET
  @Name_34cd4a32 = N'MJFormField'
SET
  @Version_34cd4a32 = N'1.0.0'
SET
  @VersionSequence_34cd4a32 = 1
SET
  @Title_34cd4a32 = N'Form Field'
SET
  @Description_34cd4a32 = N'Metadata-driven, entity-aware edit/view field input. Renders the correct control for a field by reading EntityFieldInfo: foreign keys become searchable related-entity dropdowns, value-list fields become selects, booleans become checkboxes, dates/numbers/long-text get the appropriate input, and read mode renders Email/URL/Tel/Record links. Mirrors the enhanced fields used by MemberJunction''s generated (CodeGen) entity forms.'
SET
  @Type_34cd4a32 = N'Form'
SET
  @Status_34cd4a32 = N'Published'
SET
  @Specification_34cd4a32 = N'{"name":"MJFormField","title":"Form Field","description":"Metadata-driven, entity-aware edit/view field input. Renders the correct control for a field by reading EntityFieldInfo: foreign keys become searchable related-entity dropdowns, value-list fields become selects, booleans become checkboxes, dates/numbers/long-text get the appropriate input, and read mode renders Email/URL/Tel/Record links. Mirrors the enhanced fields used by MemberJunction''s generated (CodeGen) entity forms.","type":"form","location":"embedded","functionalRequirements":"Render a single entity field as a view or edit control, driven entirely by the field''s metadata (no per-field hand coding by the consumer).\n\n- View mode: plain value, with clickable Email / URL / Tel links and clickable foreign-key / record links (via callbacks.OpenEntityRecord). Booleans show Yes/No; dates are localized.\n- Edit mode: foreign-key fields render a searchable autocomplete that queries the related entity by its name field; value-list fields render a select of allowed values; booleans render a checkbox; dates render a date input; numbers a number input; long text a textarea; otherwise a text/email/url input.\n- Read-only fields (primary keys, non-updatable, computed/virtual) always render as read display, even in edit mode.\n- Required (non-null) fields show a marker and a required-empty validation message.","technicalDesign":"Resolves field metadata from utilities.md.Entities (find by entityName, then field by fieldName). Foreign-key search and current-value name resolution use utilities.rv.RunView against the related entity (MaxRows-limited, debounced). The component is controlled: it reads `value` (falling back to record[fieldName]) and emits changes via the `onChange` callback prop, so the parent form owns draft state. It never mutates the record and never writes via BaseEntity/Metadata. No top-level imports; React is the injected global.","dataRequirements":{"mode":"props","description":"Receives the record + field name through props; resolves field metadata via utilities.md and foreign-key lookups via utilities.rv.RunView."},"properties":[{"name":"entityName","type":"string","description":"Name of the entity the field belongs to (for metadata lookup).","required":true},{"name":"fieldName","type":"string","description":"Name of the field to render.","required":true},{"name":"record","type":"Record<string, any>","description":"The bound record; used as the value fallback and for joined FK display names.","required":true},{"name":"value","type":"any","description":"Controlled value. When provided, overrides record[fieldName] (use the form''s draft value).","required":false},{"name":"mode","type":"''view'' | ''edit'' | ''create''","description":"Render mode. ''edit''/''create'' show inputs; ''view'' shows read display.","required":false,"defaultValue":"view","possibleValues":["view","edit","create"]},{"name":"editMode","type":"boolean","description":"Alternative to `mode`; true renders edit controls.","required":false},{"name":"showLabel","type":"boolean","description":"Whether to render the field label.","required":false,"defaultValue":true},{"name":"label","type":"string","description":"Override the field''s display name.","required":false}],"events":[{"name":"change","description":"Fired when the user edits the field. The parameter is the new value; wire it to the form''s draft state.","parameters":[{"name":"value","type":"any","description":"The new field value (FK id, selected value, boolean, date string, number, or text)."}]}],"dependencies":[],"code":"function MJFormField({\n  // Identity\n  entityName,\n  fieldName,\n  // Data\n  record,\n  value,            // controlled value; falls back to record[fieldName] when undefined\n  mode,             // ''view'' | ''edit'' | ''create''\n  editMode,         // boolean alternative to mode\n  // Change callback (edit mode)\n  onChange,\n  // Display options\n  showLabel = true,\n  label,            // override the field''s display name\n  // Standard interactive-component props\n  utilities,\n  styles,\n  components,\n  callbacks,\n  savedUserSettings,\n  onSaveUserSettings,\n}) {\n  // ── style helpers (degrade gracefully if a token is missing) ─────────────\n  const s = styles || {};\n  const colors = s.colors || {};\n  const spacing = s.spacing || {};\n  const typo = s.typography || {};\n  const fs = typo.fontSize || {};\n  const radius = (() => {\n    const r = s.borders && s.borders.radius;\n    return typeof r === ''object'' ? (r.sm || r.md || ''4px'') : (r || ''4px'');\n  })();\n  const text = colors.text || ''#1f2937'';\n  const textSecondary = colors.textSecondary || ''#6b7280'';\n  const border = colors.border || ''#d1d5db'';\n  const primary = colors.primary || ''#2563eb'';\n  const danger = colors.error || colors.danger || ''#dc2626'';\n  const surface = colors.surface || ''#ffffff'';\n  const pad = spacing.sm || ''8px'';\n\n  // ── metadata resolution ──────────────────────────────────────────────────\n  const entity = React.useMemo(\n    () => (utilities && utilities.md && utilities.md.Entities\n      ? utilities.md.Entities.find(e => e.Name === entityName) : null) || null,\n    [utilities, entityName],\n  );\n  const field = React.useMemo(\n    () => (entity && entity.Fields ? entity.Fields.find(f => f.Name === fieldName) : null) || null,\n    [entity, fieldName],\n  );\n\n  const editing = mode === ''edit'' || mode === ''create'' || editMode === true;\n\n  // Derived field facts (all from EntityFieldInfo)\n  const tsType = (field && field.TSType) || ''string'';\n  const ext = (field && field.ExtendedType) || null;\n  const valueListType = (field && field.ValueListTypeEnum) || ''None'';\n  const valueList = valueListType !== ''None'' && field && field.EntityFieldValues ? field.EntityFieldValues : [];\n  const relatedEntityName = (field && field.RelatedEntity) || null;\n  const isFK = !!relatedEntityName;\n  const isReadOnly = !field\n    || field.IsPrimaryKey === true\n    || field.AllowUpdateAPI === false\n    || field.ReadOnly === true\n    || field.IsVirtual === true;\n  const required = field ? field.AllowsNull === false && !field.IsPrimaryKey : false;\n  const displayName = label || (field && (field.DisplayName || field.Name)) || fieldName;\n\n  const currentValue = value !== undefined ? value : (record ? record[fieldName] : undefined);\n\n  // ── FK display-name + search state ─────────────────────────────────────────\n  const relatedEntity = React.useMemo(\n    () => (isFK && utilities && utilities.md && utilities.md.Entities\n      ? utilities.md.Entities.find(e => e.Name === relatedEntityName) : null) || null,\n    [isFK, utilities, relatedEntityName],\n  );\n  const relPK = (relatedEntity && relatedEntity.Fields && relatedEntity.Fields.find(f => f.IsPrimaryKey))\n    || null;\n  const relPKName = (field && field.RelatedEntityFieldName) || (relPK && relPK.Name) || ''ID'';\n  const relNameFieldName = (relatedEntity && relatedEntity.NameField && relatedEntity.NameField.Name)\n    || ''Name'';\n\n  const [fkDisplay, setFkDisplay] = React.useState('''');\n  const [fkSearch, setFkSearch] = React.useState('''');\n  const [fkResults, setFkResults] = React.useState([]);\n  const [fkOpen, setFkOpen] = React.useState(false);\n  const debounceRef = React.useRef(null);\n\n  // Resolve the display name for the current FK value.\n  React.useEffect(() => {\n    if (!isFK) return;\n    // 1) joined name already on the record (no fetch)\n    const mapName = field && field.RelatedEntityNameFieldMap;\n    if (mapName && record && record[mapName] != null && record[mapName] !== '''') {\n      setFkDisplay(String(record[mapName]));\n      return;\n    }\n    if (currentValue == null || currentValue === '''') { setFkDisplay(''''); return; }\n    let cancelled = false;\n    (async () => {\n      try {\n        const res = await utilities.rv.RunView({\n          EntityName: relatedEntityName,\n          ExtraFilter: `$' + CAST(N'' AS NVARCHAR(MAX)) + N'{relPKName} = ''$' + CAST(N'' AS NVARCHAR(MAX)) + N'{String(currentValue).replace(/''/g, \"''''\")}''`,\n          Fields: [relPKName, relNameFieldName],\n          MaxRows: 1,\n        });\n        if (!cancelled && res && res.Success && res.Results && res.Results.length > 0) {\n          setFkDisplay(String(res.Results[0][relNameFieldName] ?? currentValue));\n        }\n      } catch (e) { /* leave raw value */ }\n    })();\n    return () => { cancelled = true; };\n  }, [isFK, currentValue, relatedEntityName, relPKName, relNameFieldName]);\n\n  const runFkSearch = React.useCallback((q) => {\n    if (debounceRef.current) clearTimeout(debounceRef.current);\n    debounceRef.current = setTimeout(async () => {\n      try {\n        const filter = q && q.trim().length > 0\n          ? `$' + CAST(N'' AS NVARCHAR(MAX)) + N'{relNameFieldName} LIKE ''$' + CAST(N'' AS NVARCHAR(MAX)) + N'{q.replace(/''/g, \"''''\")}%''`\n          : undefined;\n        const res = await utilities.rv.RunView({\n          EntityName: relatedEntityName,\n          ExtraFilter: filter,\n          OrderBy: `$' + CAST(N'' AS NVARCHAR(MAX)) + N'{relNameFieldName} ASC`,\n          Fields: [relPKName, relNameFieldName],\n          MaxRows: 20,\n        });\n        setFkResults(res && res.Success ? (res.Results || []) : []);\n      } catch (e) { setFkResults([]); }\n    }, 250);\n  }, [relatedEntityName, relNameFieldName, relPKName]);\n\n  // ── shared visual atoms ────────────────────────────────────────────────────\n  const labelEl = showLabel ? (\n    <label style={{ display: ''block'', fontSize: fs.sm || ''13px'', fontWeight: 500, color: textSecondary, marginBottom: ''4px'' }}>\n      {displayName}{required && editing ? <span style={{ color: danger }}> *</span> : null}\n    </label>\n  ) : null;\n\n  const inputStyle = {\n    width: ''100%'',\n    padding: pad,\n    fontSize: fs.md || ''14px'',\n    color: text,\n    background: surface,\n    border: `1px solid $' + CAST(N'' AS NVARCHAR(MAX)) + N'{border}`,\n    borderRadius: radius,\n    boxSizing: ''border-box'',\n  };\n\n  const readValueStyle = {\n    padding: pad,\n    fontSize: fs.md || ''14px'',\n    color: text,\n    minHeight: ''20px'',\n    wordBreak: ''break-word'',\n  };\n\n  const fieldWrap = { marginBottom: spacing.md || ''16px'', position: ''relative'' };\n\n  // ── READ MODE ──────────────────────────────────────────────────────────────\n  if (!editing) {\n    let display;\n    if (currentValue == null || currentValue === '''') {\n      display = <span style={{ color: textSecondary, fontStyle: ''italic'' }}>—</span>;\n    } else if (tsType === ''boolean'') {\n      display = <span>{currentValue ? ''Yes'' : ''No''}</span>;\n    } else if (isFK && callbacks && callbacks.OpenEntityRecord) {\n      display = (\n        <a\n          style={{ color: primary, cursor: ''pointer'', textDecoration: ''none'' }}\n          onClick={() => callbacks.OpenEntityRecord(relatedEntityName, [{ FieldName: relPKName, Value: currentValue }])}\n          title=\"View related record\"\n        >{fkDisplay || String(currentValue)}</a>\n      );\n    } else if (ext === ''Email'') {\n      display = <a style={{ color: primary }} href={`mailto:$' + CAST(N'' AS NVARCHAR(MAX)) + N'{currentValue}`}>{String(currentValue)}</a>;\n    } else if (ext === ''URL'') {\n      display = <a style={{ color: primary }} href={String(currentValue)} target=\"_blank\" rel=\"noopener noreferrer\">{String(currentValue)}</a>;\n    } else if (ext === ''Tel'' || ext === ''SMS'') {\n      display = <a style={{ color: primary }} href={`tel:$' + CAST(N'' AS NVARCHAR(MAX)) + N'{currentValue}`}>{String(currentValue)}</a>;\n    } else if (tsType === ''Date'') {\n      const d = new Date(currentValue);\n      display = <span>{isNaN(d.getTime()) ? String(currentValue) : d.toLocaleString()}</span>;\n    } else {\n      display = <span>{String(currentValue)}</span>;\n    }\n    return (\n      <div style={fieldWrap}>\n        {labelEl}\n        <div style={readValueStyle}>{display}</div>\n      </div>\n    );\n  }\n\n  // ── EDIT MODE ────────────────────────────────────────────────────────────────\n  // Read-only fields render as read display even in edit mode.\n  if (isReadOnly) {\n    return (\n      <div style={fieldWrap}>\n        {labelEl}\n        <div style={{ ...readValueStyle, background: colors.background || ''#f3f4f6'', border: `1px solid $' + CAST(N'' AS NVARCHAR(MAX)) + N'{border}`, borderRadius: radius }}>\n          {currentValue == null || currentValue === ''''\n            ? <span style={{ color: textSecondary, fontStyle: ''italic'' }}>—</span>\n            : String(currentValue)}\n        </div>\n      </div>\n    );\n  }\n\n  const emit = (v) => { if (onChange) onChange(v); };\n  const requiredEmpty = required && (currentValue == null || currentValue === '''');\n  const borderColor = requiredEmpty ? danger : border;\n\n  let control;\n  if (isFK) {\n    control = (\n      <div style={{ position: ''relative'' }}>\n        <input\n          type=\"text\"\n          style={{ ...inputStyle, borderColor }}\n          value={fkOpen ? fkSearch : (fkDisplay || (currentValue != null ? String(currentValue) : ''''))}\n          placeholder=\"Search…\"\n          onFocus={() => { setFkOpen(true); setFkSearch(''''); runFkSearch(''''); }}\n          onChange={(e) => { setFkSearch(e.target.value); runFkSearch(e.target.value); }}\n          onBlur={() => setTimeout(() => setFkOpen(false), 150)}\n        />\n        {fkOpen && fkResults.length > 0 ? (\n          <div style={{\n            position: ''absolute'', top: ''100%'', left: 0, right: 0, zIndex: 1000,\n            background: surface, border: `1px solid $' + CAST(N'' AS NVARCHAR(MAX)) + N'{border}`, borderRadius: radius,\n            maxHeight: ''220px'', overflowY: ''auto'', boxShadow: ''0 4px 12px rgba(0,0,0,0.12)'',\n          }}>\n            {fkResults.map((r) => (\n              <div\n                key={String(r[relPKName])}\n                style={{ padding: pad, cursor: ''pointer'', fontSize: fs.md || ''14px'', color: text }}\n                onMouseDown={() => {\n                  emit(r[relPKName]);\n                  setFkDisplay(String(r[relNameFieldName] ?? r[relPKName]));\n                  setFkOpen(false);\n                }}\n                onMouseEnter={(e) => { e.currentTarget.style.background = colors.surfaceHover || ''#f3f4f6''; }}\n                onMouseLeave={(e) => { e.currentTarget.style.background = ''transparent''; }}\n              >{String(r[relNameFieldName] ?? r[relPKName])}</div>\n            ))}\n          </div>\n        ) : null}\n      </div>\n    );\n  } else if (valueList.length > 0) {\n    control = (\n      <select style={{ ...inputStyle, borderColor }} value={currentValue == null ? '''' : String(currentValue)} onChange={(e) => emit(e.target.value)}>\n        <option value=\"\">—</option>\n        {valueList.map((v) => (\n          <option key={v.Value} value={v.Value}>{v.Code || v.Value}</option>\n        ))}\n      </select>\n    );\n  } else if (tsType === ''boolean'') {\n    control = (\n      <input\n        type=\"checkbox\"\n        checked={!!currentValue}\n        onChange={(e) => emit(e.target.checked)}\n        style={{ width: ''18px'', height: ''18px'', cursor: ''pointer'' }}\n      />\n    );\n  } else if (tsType === ''Date'') {\n    const iso = currentValue ? String(currentValue).slice(0, 10) : '''';\n    control = <input type=\"date\" style={{ ...inputStyle, borderColor }} value={iso} onChange={(e) => emit(e.target.value)} />;\n  } else if (tsType === ''number'') {\n    control = <input type=\"number\" style={{ ...inputStyle, borderColor }} value={currentValue == null ? '''' : currentValue} onChange={(e) => emit(e.target.value === '''' ? null : Number(e.target.value))} />;\n  } else if (ext === ''Email'') {\n    control = <input type=\"email\" style={{ ...inputStyle, borderColor }} value={currentValue == null ? '''' : currentValue} onChange={(e) => emit(e.target.value)} />;\n  } else if (ext === ''URL'') {\n    control = <input type=\"url\" style={{ ...inputStyle, borderColor }} value={currentValue == null ? '''' : currentValue} onChange={(e) => emit(e.target.value)} />;\n  } else {\n    // long text → textarea, else single-line text\n    const isLong = field && (field.MaxLength === -1 || field.MaxLength > 255);\n    control = isLong\n      ? <textarea rows={4} style={{ ...inputStyle, borderColor, resize: ''vertical'' }} value={currentValue == null ? '''' : currentValue} onChange={(e) => emit(e.target.value)} />\n      : <input type=\"text\" style={{ ...inputStyle, borderColor }} value={currentValue == null ? '''' : currentValue} onChange={(e) => emit(e.target.value)} />;\n  }\n\n  return (\n    <div style={fieldWrap}>\n      {labelEl}\n      {control}\n      {requiredEmpty ? (\n        <div style={{ color: danger, fontSize: fs.sm || ''12px'', marginTop: ''4px'' }}>{displayName} is required.</div>\n      ) : null}\n    </div>\n  );\n}\n","exampleUsage":"<MJFormField\n  entityName={entityName}\n  fieldName={f.name}\n  record={record}\n  value={f.name in draft ? draft[f.name] : record?.[f.name]}\n  mode={mode}\n  onChange={(v) => setField(f.name, v)}\n  utilities={utilities}\n  styles={styles}\n  components={components}\n  callbacks={callbacks}\n/>"}'
SET
  @FunctionalRequirements_34cd4a32 = N'Render a single entity field as a view or edit control, driven entirely by the field''s metadata (no per-field hand coding by the consumer).

- View mode: plain value, with clickable Email / URL / Tel links and clickable foreign-key / record links (via callbacks.OpenEntityRecord). Booleans show Yes/No; dates are localized.
- Edit mode: foreign-key fields render a searchable autocomplete that queries the related entity by its name field; value-list fields render a select of allowed values; booleans render a checkbox; dates render a date input; numbers a number input; long text a textarea; otherwise a text/email/url input.
- Read-only fields (primary keys, non-updatable, computed/virtual) always render as read display, even in edit mode.
- Required (non-null) fields show a marker and a required-empty validation message.'
SET
  @TechnicalDesign_34cd4a32 = N'Resolves field metadata from utilities.md.Entities (find by entityName, then field by fieldName). Foreign-key search and current-value name resolution use utilities.rv.RunView against the related entity (MaxRows-limited, debounced). The component is controlled: it reads `value` (falling back to record[fieldName]) and emits changes via the `onChange` callback prop, so the parent form owns draft state. It never mutates the record and never writes via BaseEntity/Metadata. No top-level imports; React is the injected global.'
SET
