SET
  @ID_0460f6e7 = 'C24CAE38-1982-4604-8C8D-ABC50C22036D'
SET
  @Namespace_0460f6e7 = N'Generic/UI/Form'
SET
  @Name_0460f6e7 = N'MJFormFields'
SET
  @Version_0460f6e7 = N'1.0.0'
SET
  @VersionSequence_0460f6e7 = 1
SET
  @Title_0460f6e7 = N'Form Fields (Sectioned)'
SET
  @Description_0460f6e7 = N'Renders an entity''s complete editable field set, grouped into sections by EntityField.Category / GeneratedFormSectionType — the same sectioned layout (e.g. ''Personal Information'', ''Professional Profile'', collapsed ''System Metadata'') as MemberJunction''s generated (CodeGen) forms. Each field renders through MJFormField, so foreign keys become searchable dropdowns, value lists become selects, etc. Drop this into a form''s edit mode and every field is present, sectioned, and enhanced with no per-field hand coding.'
SET
  @Type_0460f6e7 = N'Form'
SET
  @Status_0460f6e7 = N'Published'
SET
  @Specification_0460f6e7 = N'{"name":"MJFormFields","title":"Form Fields (Sectioned)","description":"Renders an entity''s complete editable field set, grouped into sections by EntityField.Category / GeneratedFormSectionType — the same sectioned layout (e.g. ''Personal Information'', ''Professional Profile'', collapsed ''System Metadata'') as MemberJunction''s generated (CodeGen) forms. Each field renders through MJFormField, so foreign keys become searchable dropdowns, value lists become selects, etc. Drop this into a form''s edit mode and every field is present, sectioned, and enhanced with no per-field hand coding.","type":"form","location":"embedded","functionalRequirements":"Read the entity''s fields from metadata and lay them out exactly like CodeGen forms:\n- Skip computed/virtual fields.\n- Route by GeneratedFormSectionType: ''Top'' fields render above the sections (no heading); ''Category'' fields group under their Category (default ''Details''); others fall into ''Details''.\n- Primary-key and audit fields (__mj_*, CreatedAt, UpdatedAt) go into a collapsed ''System Metadata'' section, shown read-only.\n- Sections are collapsible; collapse state persists via savedUserSettings.\n- Every non-system field is rendered (no hand-picking).","technicalDesign":"Resolves the entity from utilities.md.Entities and groups its Fields (sorted by Sequence) using field.Category + field.GeneratedFormSectionType, mirroring buildDefaultFormScaffold. Renders each field via the MJFormField dependency, passing value = draft[field] ?? record[field] and emitting changes via onFieldChange(fieldName, value). The component is presentational + controlled: the parent form owns draft state and the save lifecycle; this component never mutates the record or writes via BaseEntity/Metadata. No top-level imports; React is the injected global.","dataRequirements":{"mode":"props","description":"Receives the record + draft through props; resolves field metadata (Category, section type, FK, value lists) via utilities.md."},"properties":[{"name":"entityName","type":"string","description":"Name of the bound entity (for metadata lookup).","required":true},{"name":"record","type":"Record<string, any>","description":"The bound record; per-field value fallback.","required":true},{"name":"draft","type":"Record<string, any>","description":"Map of field name -> edited value (the form''s draft state). Overrides record values per field.","required":false},{"name":"mode","type":"''view'' | ''edit'' | ''create''","description":"Render mode passed through to each field.","required":false,"defaultValue":"view","possibleValues":["view","edit","create"]},{"name":"editMode","type":"boolean","description":"Alternative to `mode`.","required":false},{"name":"excludeFields","type":"Array<string>","description":"Field names to omit (e.g. fields already featured in a custom header).","required":false},{"name":"showSystemSection","type":"boolean","description":"Whether to render the collapsed ''System Metadata'' section (PK + audit fields, read-only).","required":false,"defaultValue":true}],"events":[{"name":"fieldChange","description":"Fired when any field is edited. Wire it to the form''s draft state.","parameters":[{"name":"fieldName","type":"string","description":"The field that changed."},{"name":"value","type":"any","description":"The new value."}]}],"dependencies":[{"name":"MJFormField","namespace":"Generic/UI/Form","location":"registry","description":"Per-field enhanced input (FK search, value lists, dates, validation, links)."}],"code":"function MJFormFields({\n  // Identity + data\n  entityName,\n  record,\n  draft,                 // map of field -> edited value (the form''s draft state)\n  mode,                  // ''view'' | ''edit'' | ''create''\n  editMode,              // boolean alternative to mode\n  onFieldChange,         // (fieldName, value) => void\n  // Options\n  excludeFields,         // string[] of field names to omit\n  showSystemSection = true,\n  // Standard interactive-component props\n  utilities,\n  styles,\n  components,\n  callbacks,\n  savedUserSettings,\n  onSaveUserSettings,\n}) {\n  const { MJFormField } = components || {};\n  const d = draft || {};\n\n  // ── style helpers ──────────────────────────────────────────────────────────\n  const s = styles || {};\n  const colors = s.colors || {};\n  const spacing = s.spacing || {};\n  const typo = s.typography || {};\n  const fsz = typo.fontSize || {};\n  const text = colors.text || ''#1f2937'';\n  const textSecondary = colors.textSecondary || ''#6b7280'';\n  const border = colors.border || ''#e5e7eb'';\n  const surface = colors.surface || ''#ffffff'';\n  const radius = (() => { const r = s.borders && s.borders.radius; return typeof r === ''object'' ? (r.md || r.sm || ''8px'') : (r || ''8px''); })();\n  const lg = spacing.lg || ''20px'';\n  const md = spacing.md || ''16px'';\n\n  // ── metadata + section layout (mirrors MJ CodeGen / scaffold) ────────────────\n  const entity = React.useMemo(\n    () => (utilities && utilities.md && utilities.md.Entities\n      ? utilities.md.Entities.find(e => e.Name === entityName) : null) || null,\n    [utilities, entityName],\n  );\n\n  const layout = React.useMemo(() => {\n    const result = { top: [], sections: [], system: [] };\n    if (!entity || !entity.Fields) return result;\n    const exclude = new Set(excludeFields || []);\n    const sectionMap = new Map(); // title -> fields[]\n    const sorted = [...entity.Fields].sort((a, b) => (a.Sequence ?? 0) - (b.Sequence ?? 0));\n    for (const f of sorted) {\n      if (exclude.has(f.Name)) continue;\n      if (f.IsVirtual) continue;                                   // computed / joined — skip (matches scaffold)\n      const isAudit = f.Name.startsWith(''__mj_'') || f.Name === ''CreatedAt'' || f.Name === ''UpdatedAt'';\n      if (f.IsPrimaryKey || isAudit) { result.system.push(f); continue; }\n      switch (f.GeneratedFormSectionType) {\n        case ''Top'':\n          result.top.push(f);\n          break;\n        case ''Category'': {\n          const cat = (f.Category && f.Category.trim()) || ''Details'';\n          if (!sectionMap.has(cat)) sectionMap.set(cat, []);\n          sectionMap.get(cat).push(f);\n          break;\n        }\n        default: {\n          if (!sectionMap.has(''Details'')) sectionMap.set(''Details'', []);\n          sectionMap.get(''Details'').push(f);\n        }\n      }\n    }\n    result.sections = [...sectionMap.entries()].map(([title, fields]) => ({ title, fields }));\n    return result;\n  }, [entity, excludeFields]);\n\n  // ── collapse state (persisted) ───────────────────────────────────────────────\n  const [collapsed, setCollapsed] = React.useState(() => (savedUserSettings && savedUserSettings.collapsedSections) || {});\n  const toggle = (title) => {\n    setCollapsed(prev => {\n      const next = { ...prev, [title]: !prev[title] };\n      if (onSaveUserSettings) onSaveUserSettings({ ...savedUserSettings, collapsedSections: next });\n      return next;\n    });\n  };\n\n  // ── field + section rendering ─────────────────────────────────────────────────\n  const renderField = (f) => (\n    MJFormField\n      ? <MJFormField\n          key={f.Name}\n          entityName={entityName}\n          fieldName={f.Name}\n          record={record}\n          value={f.Name in d ? d[f.Name] : (record ? record[f.Name] : undefined)}\n          mode={mode}\n          editMode={editMode}\n          onChange={(v) => { if (onFieldChange) onFieldChange(f.Name, v); }}\n          utilities={utilities}\n          styles={styles}\n          components={components}\n          callbacks={callbacks}\n        />\n      : (\n        <div key={f.Name} style={{ marginBottom: md }}>\n          <label style={{ display: ''block'', fontWeight: 500, color: textSecondary }}>{f.Name}</label>\n          <div>{String((record && record[f.Name]) ?? '''')}</div>\n        </div>\n      )\n  );\n\n  const fieldGrid = (fields) => (\n    <div style={{ display: ''grid'', gridTemplateColumns: ''repeat(auto-fill, minmax(260px, 1fr))'', gap: md }}>\n      {fields.map(renderField)}\n    </div>\n  );\n\n  const renderSection = (title, fields, defaultCollapsed) => {\n    const isCollapsed = title in collapsed ? collapsed[title] : !!defaultCollapsed;\n    return (\n      <div key={title} style={{ border: `1px solid $' + CAST(N'' AS NVARCHAR(MAX)) + N'{border}`, borderRadius: radius, background: surface, marginBottom: lg, overflow: ''hidden'' }}>\n        <div\n          onClick={() => toggle(title)}\n          style={{ display: ''flex'', justifyContent: ''space-between'', alignItems: ''center'', cursor: ''pointer'', padding: `$' + CAST(N'' AS NVARCHAR(MAX)) + N'{md} $' + CAST(N'' AS NVARCHAR(MAX)) + N'{lg}`, borderBottom: isCollapsed ? ''none'' : `1px solid $' + CAST(N'' AS NVARCHAR(MAX)) + N'{border}`, fontWeight: 600, fontSize: fsz.lg || ''16px'', color: text }}\n        >\n          <span>{title}</span>\n          <span style={{ color: textSecondary, fontSize: ''12px'' }}>{isCollapsed ? ''▸'' : ''▾''}</span>\n        </div>\n        {!isCollapsed ? <div style={{ padding: lg }}>{fieldGrid(fields)}</div> : null}\n      </div>\n    );\n  };\n\n  if (!entity) {\n    return <div style={{ padding: md, color: textSecondary }}>Loading fields…</div>;\n  }\n\n  return (\n    <div>\n      {layout.top.length > 0 ? <div style={{ marginBottom: lg }}>{fieldGrid(layout.top)}</div> : null}\n      {layout.sections.map(sec => renderSection(sec.title, sec.fields, false))}\n      {showSystemSection && layout.system.length > 0 ? renderSection(''System Metadata'', layout.system, true) : null}\n    </div>\n  );\n}\n","exampleUsage":"<MJFormFields\n  entityName={entityName}\n  record={record}\n  draft={draft}\n  mode={mode}\n  onFieldChange={(field, value) => setField(field, value)}\n  utilities={utilities}\n  styles={styles}\n  components={components}\n  callbacks={callbacks}\n  savedUserSettings={savedUserSettings}\n  onSaveUserSettings={onSaveUserSettings}\n/>"}'
SET
  @FunctionalRequirements_0460f6e7 = N'Read the entity''s fields from metadata and lay them out exactly like CodeGen forms:
- Skip computed/virtual fields.
- Route by GeneratedFormSectionType: ''Top'' fields render above the sections (no heading); ''Category'' fields group under their Category (default ''Details''); others fall into ''Details''.
- Primary-key and audit fields (__mj_*, CreatedAt, UpdatedAt) go into a collapsed ''System Metadata'' section, shown read-only.
- Sections are collapsible; collapse state persists via savedUserSettings.
- Every non-system field is rendered (no hand-picking).'
SET
  @TechnicalDesign_0460f6e7 = N'Resolves the entity from utilities.md.Entities and groups its Fields (sorted by Sequence) using field.Category + field.GeneratedFormSectionType, mirroring buildDefaultFormScaffold. Renders each field via the MJFormField dependency, passing value = draft[field] ?? record[field] and emitting changes via onFieldChange(fieldName, value). The component is presentational + controlled: the parent form owns draft state and the save lifecycle; this component never mutates the record or writes via BaseEntity/Metadata. No top-level imports; React is the injected global.'
SET
